/* Aula 06 — modelJs: Operadores e decisões */

// 1) == vs ===
console.log(5 == '5');   // true
console.log(5 === '5');  // false
console.log('' == 0);    // true (coerção)
console.log('' === 0);   // false

// 2) Comparação
const idade = 17;
const podeEntrar = idade >= 18;
console.log('podeEntrar:', podeEntrar);

// 3) Lógicos
const temCupom = true;
const compraMinima = false;
const desconto = temCupom && compraMinima;
console.log('desconto:', desconto); // false

// 4) Fallback com ||
const apelido = '';
const nome = 'Bruno';
const nomeExibido = apelido || nome;
console.log('nomeExibido:', nomeExibido);

// 5) Ternário
const status = podeEntrar ? 'Acesso liberado' : 'Acesso negado';
console.log('status:', status);
